pointLocator.script:
hora =ts.hour;
minuto = ts.minute;
segundo = ts.second;
dia = ts.day;
mes = ts.month;
ano = ts.year;


if (dia< 10){
dia= "0"+dia;
} else {
dia= dia;
}

if (mes < 10){
mes = "0"+mes;
} else {
mes = mes;
}

if (hora< 10){
hora= "0"+hora;
} else {
hora= hora;
}

if (minuto< 10){
minuto= "0"+minuto;
} else {
minuto= minuto;
}

if (segundo< 10){
segundo= "0"+segundo;
} else {
segundo= segundo;
}

return ""+dia+"/"+mes+"/"+ano+" - "+hora+":"+minuto+":"+segundo
